SELECT c.*, m.name as category_name
FROM media_content c
LEFT JOIN media_category m ON c.category_id = m.id
WHERE c.del_flag = '0'

    AND c.title LIKE CONCAT('%', #{title}, '%')


    AND c.type = #{type}


    AND c.category_id = #{categoryId}


    AND c.status = #{status}

ORDER BY c.create_time DESC

